from dataclasses import dataclass

@dataclass
class RequestLimits:
    max_input_tokens: int = 4096
    max_output_tokens: int = 2048
    max_retrieved_chunks: int = 10
    max_chunk_tokens: int = 512  # per retrieved chunk

    def validate_request(self, input_tokens: int, chunk_count: int) -> list[str]:
        violations = []
        if input_tokens > self.max_input_tokens:
            violations.append(
                f"Input too large: {input_tokens} > {self.max_input_tokens} tokens"
            )
        if chunk_count > self.max_retrieved_chunks:
            violations.append(
                f"Too many chunks: {chunk_count} > {self.max_retrieved_chunks}"
            )
        return violations

# Detect sponge prompt patterns in user input
_SPONGE_PATTERNS = [
    "translate to",
    "in every language",
    "repeat 100 times",
    "write a complete",
    "think through every",
]

def is_sponge_prompt(text: str) -> bool:
    text_lower = text.lower()
    return sum(p in text_lower for p in _SPONGE_PATTERNS) >= 2

from dataclasses import dataclass
from enum import Enum
from typing import Callable

class Role(Enum):
    VIEWER = "viewer"
    USER = "user"
    ADMIN = "admin"

@dataclass
class ToolCall:
    tool_name: str
    parameters: dict

# Define which roles can invoke which tools
TOOL_PERMISSIONS: dict[str, set[Role]] = {
    "search_documents": {Role.VIEWER, Role.USER, Role.ADMIN},
    "summarize_document": {Role.VIEWER, Role.USER, Role.ADMIN},
    "send_email": {Role.USER, Role.ADMIN},
    "delete_document": {Role.ADMIN},
    "create_user": {Role.ADMIN},
}

class PrivilegeEscalationGuard:
    def __init__(self, user_role: Role):
        self.user_role = user_role

    def check(self, tool_call: ToolCall) -> None:
        allowed_roles = TOOL_PERMISSIONS.get(tool_call.tool_name, set())
        if self.user_role not in allowed_roles:
            raise PermissionError(
                f"Role {self.user_role.value} cannot invoke tool "
                f"'{tool_call.tool_name}'. Possible prompt injection attempt."
            )

# Critical: tool permission checks must happen OUTSIDE the LLM loop.
# Never let the model gate-check itself — an injected instruction can
# instruct the model to report that it has the required permissions.
guard = PrivilegeEscalationGuard(user_role=Role.USER)
try:
    guard.check(ToolCall("delete_document", {"id": "doc_123"}))
except PermissionError as e:
    print(f"SECURITY: {e}")
